export type PrismaPromise<T> = $Public.PrismaPromise<T>


/**
 * Model Contact
 * A person or organisation in the CRM.
 * Supports full lead-to-customer lifecycle with AI-assisted lead scoring.
 */
export type Contact = $Result.DefaultSelection<Prisma.$ContactPayload>
/**
 * Model ContactNote
 * Interaction log entry for a Contact.
 * Types: "call" | "email" | "meeting" | "task" | "note"
 */
export type ContactNote = $Result.DefaultSelection<Prisma.$ContactNotePayload>
/**
 * Model Product
 * A physical product, digital good, or billable service.
 */
export type Product = $Result.DefaultSelection<Prisma.$ProductPayload>
/**
 * Model Warehouse
 * A physical storage location — warehouse, store room, or virtual dropship.
 */
export type Warehouse = $Result.DefaultSelection<Prisma.$WarehousePayload>
/**
 * Model InventoryItem
 * Current stock position for a Product at a Warehouse.
 * quantityAvailable = quantityOnHand - quantityReserved
 */
export type InventoryItem = $Result.DefaultSelection<Prisma.$InventoryItemPayload>
/**
 * Model StockMovement
 * Immutable audit log for every stock quantity change.
 */
export type StockMovement = $Result.DefaultSelection<Prisma.$StockMovementPayload>
/**
 * Model Order
 * A sales order — from Draft quote through final Delivery.
 * Status transitions emit order.created / order.fulfilled Kafka events.
 */
export type Order = $Result.DefaultSelection<Prisma.$OrderPayload>
/**
 * Model OrderItem
 * A single line on an Order.
 * Tracks snapshot pricing and per-item fulfillment / return quantities.
 */
export type OrderItem = $Result.DefaultSelection<Prisma.$OrderItemPayload>
/**
 * Model Fulfillment
 * A physical shipment event.
 * Multiple fulfillments per order support split-shipment scenarios.
 */
export type Fulfillment = $Result.DefaultSelection<Prisma.$FulfillmentPayload>
/**
 * Model Invoice
 * An invoice — standalone or linked to an Order.
 * Supports recurring billing via recurringTemplateId self-relation.
 * nextGenerationAt is polled by the scheduler to auto-generate instances.
 */
export type Invoice = $Result.DefaultSelection<Prisma.$InvoicePayload>
/**
 * Model InvoiceLine
 * A line item on an Invoice — optionally linked to a Product.
 */
export type InvoiceLine = $Result.DefaultSelection<Prisma.$InvoiceLinePayload>
/**
 * Model Payment
 * A payment applied against an Invoice.
 * Multiple records support partial-payment workflows.
 */
export type Payment = $Result.DefaultSelection<Prisma.$PaymentPayload>
/**
 * Model Expense
 * An expense record with optional receipt image capture and OCR extraction.
 * Feeds into v_pnl_monthly and the Finance Agent cost analysis.
 */
export type Expense = $Result.DefaultSelection<Prisma.$ExpensePayload>
/**
 * Model Report
 * A saved report definition — parameters for on-demand or scheduled execution.
 * Computed output is cached in data and versioned via ReportSnapshot.
 */
export type Report = $Result.DefaultSelection<Prisma.$ReportPayload>
/**
 * Model ReportSnapshot
 * Immutable historical snapshot of a Report computed output.
 */
export type ReportSnapshot = $Result.DefaultSelection<Prisma.$ReportSnapshotPayload>
/**
 * Model PnlMonthly
 * Monthly P&L aggregation.
 * Revenue = paid Invoice totals. Expenses = approved Expense amounts.
 */
export type PnlMonthly = $Result.DefaultSelection<Prisma.$PnlMonthlyPayload>
/**
 * Model ArAging
 * Accounts-receivable aging view.
 * Classifies outstanding Invoice.amountDue into standard aging buckets.
 */
export type ArAging = $Result.DefaultSelection<Prisma.$ArAgingPayload>
/**
 * Model LowStockAlert
 * Inventory items at or below their reorderPoint.
 * Polled by the Kafka inventory.low event publisher service.
 */
export type LowStockAlert = $Result.DefaultSelection<Prisma.$LowStockAlertPayload>

